// Wire contract between the QEMU TCG plugin and vsim. Both sides write/read
// `struct hybrid_state_v1` byte-for-byte through a shared file.
//
// Stability: never repurpose offsets within a published version. Add new
// fields by consuming bytes from `reserved`, or by introducing v2 alongside.
//
// C and C++ both compile this header.

#ifndef HYBRID_STATE_ABI_H
#define HYBRID_STATE_ABI_H

#include <stdint.h>
#include <stddef.h>

#ifdef __cplusplus
extern "C" {
#endif

#define HYBRID_STATE_MAGIC   0x42594841u  // 'AHYB' little-endian
#define HYBRID_STATE_VERSION 1u

#define HYBRID_FLAG_RV64 (1u << 0)
#define HYBRID_FLAG_FP   (1u << 1)
#define HYBRID_FLAG_V    (1u << 2)

// VLEN upper bound, in bytes. Source of truth: data/configs/ax45mpv_premium.cfg
// which sets `NDS_VLEN 512` (-> 64 bytes per vector register). When that
// configured value changes, this constant must be updated in lock-step so
// the wire-format struct grows or shrinks to match the configured RVV width.
#define HYBRID_VLEN_BYTES_MAX 64

// 64 PMP entries; pmpcfg slots reserved at 16 so the layout works for both
// RV64 (8 entries/CSR) and a future RV32 (4 entries/CSR) packing.
#define HYBRID_PMP_CFG_NUM  16
#define HYBRID_PMP_ADDR_NUM 64

// All fields are naturally 8-byte aligned, so __attribute__((packed)) is
// unnecessary and would force unaligned access codegen. Layout is locked by
// the static_asserts in state_abi_check.h.
struct hybrid_state_v1 {
  uint32_t magic;
  uint32_t version;
  uint32_t flags;
  uint32_t hart_id;
  uint64_t pc;
  uint64_t priv;  // 0=U, 1=S, 3=M

  uint64_t gpr[32];
  uint64_t fpr[32];

  uint64_t mstatus;
  uint64_t mepc;
  uint64_t mtvec;
  uint64_t mcause;
  uint64_t mtval;
  uint64_t mscratch;
  uint64_t medeleg;
  uint64_t mideleg;
  uint64_t mip;
  uint64_t mie;
  uint64_t mcycle;
  uint64_t minstret;
  uint64_t satp;

  uint64_t pmpcfg[HYBRID_PMP_CFG_NUM];
  uint64_t pmpaddr[HYBRID_PMP_ADDR_NUM];

  uint64_t vstart;
  uint64_t vtype;
  uint64_t vl;
  uint64_t vlenb;
  uint8_t  vreg[32 * HYBRID_VLEN_BYTES_MAX];
  uint64_t vxsat;
  uint64_t vxrm;
  uint64_t vcsr;

  uint8_t  reserved[232];  // zero-initialise on write; 256 - 3*8 (vxsat/vxrm/vcsr)
};

#ifdef __cplusplus
}  // extern "C"
#endif

#include "hybrid/state_abi_check.h"

#endif  // HYBRID_STATE_ABI_H

// V-register transport via shared scratch RAM. The vsim Debug Module
// abstract-command space does not allocate slots for v0..v31 (RISC-V Debug
// Spec leaves V to optional Program Buffer or implementation-specific
// extensions), and the AX45MPV CPU wrapper does not export a DPI probe for
// the V regfile. As a stop-gap that keeps Phase 5 (DPI / PB) deferred while
// still letting C-level RVV fixtures round-trip:
//
//   - On resume from QEMU 1, vsim copies state.vreg[] into a fixed scratch
//     region of guest RAM (kVScratchGpa). The fixture's vsim-phase prologue
//     issues `vle8.v vN, (t0)` against that region to repopulate v0..v31.
//   - Before the vsim->QEMU2 drain trigger, the fixture issues `vse8.v vN,
//     (t0)` to write the (possibly mutated) regfile back to the same region.
//     vsim's StateDrain side reads the scratch bytes into state.vreg[] so
//     qemu_handback can ship them to QEMU 2 via the existing gdbstub P
//     packets.
//
// The contract is fixture-aware: any program that wants V state preserved
// across the vsim boundary must perform the load/store at the boundaries.
// rt_c_v_regs.c demonstrates the pattern. Phase 5 will replace this with a
// transparent mechanism (PB or DPI) so benchmark binaries don't need to be
// modified.
//
// Pure logic: no SystemC, no DMI bus. Easy to unit-test.

#pragma once

#include "hybrid/state_abi.h"

#include <cstddef>
#include <cstdint>
#include <cstring>
#include <span>
#include <stdexcept>

namespace hybrid
{

// Top of QEMU virt's default 128 MiB RAM (RAM_BASE 0x80000000 + 0x0FF0000
// = 0x80FF0000). Below the C-runtime stack at 0x80700000 only when the
// runtime grows beyond default; rt_c.ld places _stack at 0x80700000 so
// 0x80FF0000 sits well above it. Document the reservation in fixture
// comments so future memory-layout changes don't collide.
inline constexpr uint64_t kVScratchGpa = 0x80FF0000ull;

// Total scratch bytes needed: 32 V regs × HYBRID_VLEN_BYTES_MAX. Sized to
// the maximum supported VLEN; the actual per-reg byte count is `vlenb`.
inline constexpr std::size_t kVScratchBytes =
  static_cast<std::size_t>(32) * HYBRID_VLEN_BYTES_MAX;

namespace detail
{

// Translate scratch GPA into a byte offset inside a RAM span whose first
// byte sits at `ram_base`. Throws if the scratch region falls outside the
// supplied span (i.e. the caller passed a too-small RAM mapping).
inline auto scratch_offset(std::size_t ram_size, uint64_t ram_base)
  -> std::size_t
{
  if (kVScratchGpa < ram_base)
    throw std::runtime_error(
      "v_regfile_xfer: scratch GPA below RAM base");
  const auto off = static_cast<std::size_t>(kVScratchGpa - ram_base);
  if (off + kVScratchBytes > ram_size)
    throw std::runtime_error(
      "v_regfile_xfer: scratch region exceeds RAM span");
  return off;
}

}  // namespace detail

// Copy state.vreg[] into ram[scratch_offset .. scratch_offset+kVScratchBytes].
// Called just before vsim resumes the hart so the fixture can vle8.v from
// scratch and pick up QEMU 1's V values.
inline void stage_v_to_scratch(const hybrid_state_v1& state,
                               std::span<uint8_t> ram,
                               uint64_t ram_base)
{
  const auto off = detail::scratch_offset(ram.size(), ram_base);
  std::memcpy(ram.data() + off, state.vreg, kVScratchBytes);
}

// Copy ram[scratch_offset .. +kVScratchBytes] into state.vreg[]. Called
// inside the vsim drain path after the fixture's prologue vse8.v has
// settled the (possibly mutated) regfile bytes into RAM.
inline void read_v_from_scratch(hybrid_state_v1& state,
                                std::span<const uint8_t> ram,
                                uint64_t ram_base)
{
  const auto off = detail::scratch_offset(ram.size(), ram_base);
  std::memcpy(state.vreg, ram.data() + off, kVScratchBytes);
}

}  // namespace hybrid

