1	// Spawns qemu-system-riscv64 with -gdb tcp::PORT -S -semihosting and
2	// restores architectural state via the gdbstub before sending `c`. Waits
3	// for QEMU to exit and propagates its process exit code.
4	//
5	// Used by main.cpp when `Simulator::run()` returns kExitHandoffToQemu and
6	// `--qemu-binary` is set.
7	
8	#pragma once
9	
10	#include "hybrid/exit_codes.hpp"
11	#include "hybrid/gdbstub_session.hpp"
12	#include "hybrid/reg_names.h"
13	#include "hybrid/state_abi.h"
14	
15	#include <spdlog/spdlog.h>
16	
17	#include <arpa/inet.h>
18	#include <fcntl.h>
19	#include <netinet/in.h>
20	#include <sys/socket.h>
21	#include <sys/types.h>
22	#include <sys/wait.h>
23	#include <unistd.h>
24	
25	#include <cerrno>
26	#include <chrono>
27	#include <cstdint>
28	#include <cstdlib>
29	#include <cstring>
30	#include <stdexcept>
31	#include <string>
32	#include <thread>
33	#include <vector>
34	
35	namespace hybrid
36	{
37	
38	namespace detail
39	{
40	
41	inline auto pick_free_port() -> uint16_t
42	{
43	  const int s = ::socket(AF_INET, SOCK_STREAM, 0);
44	  if (s < 0)
45	    throw std::runtime_error("pick_free_port: socket");
46	
47	  sockaddr_in addr{};
48	  addr.sin_family      = AF_INET;
49	  addr.sin_addr.s_addr = htonl(INADDR_LOOPBACK);
50	  addr.sin_port        = 0;
51	
52	  if (::bind(s, reinterpret_cast<sockaddr*>(&addr), sizeof(addr)) < 0) {
53	    ::close(s);
54	    throw std::runtime_error("pick_free_port: bind");
55	  }
56	  socklen_t len = sizeof(addr);
57	  if (::getsockname(s, reinterpret_cast<sockaddr*>(&addr), &len) < 0) {
58	    ::close(s);
59	    throw std::runtime_error("pick_free_port: getsockname");
60	  }
61	  ::close(s);
62	  return ntohs(addr.sin_port);
63	}
64	
65	// Thrown by connect_loopback when the watched child exits before the
66	// gdbstub becomes reachable (typically: bad --qemu-binary path).
67	struct ChildExitedDuringConnect
68	{
69	  int status;
70	};
71	
72	inline auto connect_loopback(uint16_t port,
73	                             std::chrono::milliseconds timeout,
74	                             pid_t child_pid = -1) -> int
75	{
76	  const auto deadline = std::chrono::steady_clock::now() + timeout;
77	  while (std::chrono::steady_clock::now() < deadline) {
78	    const int s = ::socket(AF_INET, SOCK_STREAM, 0);
79	    if (s < 0)
80	      throw std::runtime_error("connect_loopback: socket");
81	    sockaddr_in addr{};
82	    addr.sin_family      = AF_INET;
83	    addr.sin_addr.s_addr = htonl(INADDR_LOOPBACK);
84	    addr.sin_port        = htons(port);
85	    if (::connect(s, reinterpret_cast<sockaddr*>(&addr), sizeof(addr)) == 0)
86	      return s;
87	    ::close(s);
88	    if (child_pid > 0) {
89	      int wstat = 0;
90	      if (::waitpid(child_pid, &wstat, WNOHANG) == child_pid) {
91	        int status = -1;
92	        if (WIFEXITED(wstat)) status = WEXITSTATUS(wstat);
93	        else if (WIFSIGNALED(wstat)) status = 128 + WTERMSIG(wstat);
94	        throw ChildExitedDuringConnect{status};
95	      }
96	    }
97	    std::this_thread::sleep_for(std::chrono::milliseconds(20));
98	  }
99	  throw std::runtime_error("connect_loopback: timed out waiting for QEMU "
100	                           "gdbstub");
101	}
102	
103	inline auto spawn_qemu(const std::string& binary,
104	                       const std::string& elf,
105	                       uint16_t gdb_port,
106	                       const std::string& shared_mem_path = {},
107	                       uint64_t shared_mem_size = 0) -> pid_t
108	{
109	  const pid_t pid = ::fork();
110	  if (pid < 0)
111	    throw std::runtime_error(std::string{"spawn_qemu: fork: "}
112	                             + std::strerror(errno));
113	  if (pid == 0) {
114	    // Detach the child from the caller's tty. -nographic makes QEMU's
115	    // chardev backend tcsetattr() stdin into raw mode; if the caller is
116	    // launched from a non-foreground process group (e.g. under timeout(1)),
117	    // that touch raises SIGTTOU/SIGTTIN and stops QEMU 2, hanging vsim's
118	    // waitpid. /dev/null sidesteps the tty entirely.
119	    const int devnull = ::open("/dev/null", O_RDONLY | O_CLOEXEC);
120	    if (devnull >= 0) {
121	      ::dup2(devnull, STDIN_FILENO);
122	      ::close(devnull);
123	    }
124	
125	    const std::string gdb_arg = "tcp::" + std::to_string(gdb_port);
126	    const std::string mem_obj = "memory-backend-file,id=mem,share=on,mem-path="
127	                              + shared_mem_path
128	                              + ",size=" + std::to_string(shared_mem_size);
129	    std::vector<const char*> argv;
130	    argv.push_back(binary.c_str());
131	    if (!shared_mem_path.empty()) {
132	      argv.push_back("-object");
133	      argv.push_back(mem_obj.c_str());
134	      argv.push_back("-machine");
135	      argv.push_back("virt,memory-backend=mem");
136	    } else {
137	      argv.push_back("-M");
138	      argv.push_back("virt");
139	    }
140	    // -cpu andes-ax45mpv,vlen=512: matches QEMU 1's CPU and the vsim RTL
141	    // build (NDS_VLEN 512). Without this, QEMU 2 defaults to plain rv64
142	    // (no V), mstatus.VS becomes read-only zero, and vsetvli traps with
143	    // illegal-instruction as soon as a V-using fixture's Phase 3 runs.
144	    // Andes vendor CSRs touched by the runtime crt0 (mcache_ctl, mmisc_ctl,
145	    // ...) are also gated here.
146	    argv.push_back("-cpu");
147	    argv.push_back("andes-ax45mpv,vlen=512");
148	    argv.push_back("-bios");
149	    argv.push_back("none");
150	    argv.push_back("-nographic");
151	    argv.push_back("-semihosting-config");
152	    argv.push_back("enable=on,target=native");
153	    argv.push_back("-kernel");
154	    argv.push_back(elf.c_str());
155	    argv.push_back("-gdb");
156	    argv.push_back(gdb_arg.c_str());
157	    argv.push_back("-S");
158	    argv.push_back(nullptr);
159	
160	    ::execv(binary.c_str(), const_cast<char* const*>(argv.data()));
161	    std::fprintf(stderr, "exec %s: %s\n", binary.c_str(),
162	                 std::strerror(errno));
163	    ::_exit(127);
164	  }
165	  return pid;
166	}
167	
168	}  // namespace detail
169	
170	namespace detail
171	{
172	
173	// Fetches a qXfer:features:read annex in full, looping while the stub
174	// answers with the 'm' (more) marker. QEMU's RISC-V CSR XML is ~6 KB and
175	// PacketSize is typically 1000 bytes, so several iterations are normal.
176	inline auto fetch_feature_xml(gdbstub::Session& sess, const std::string& annex)
177	  -> std::string
178	{
179	  std::string accum;
180	  std::size_t offset = 0;
181	  // Use a chunk size below the QEMU default PacketSize=1000. Asking for
182	  // 0x100 keeps each frame well under the wire limit even after the 'm'
183	  // marker and packet framing overhead.
184	  constexpr std::size_t kChunk = 0x100;
185	  while (true) {
186	    char buf[64];
187	    std::snprintf(buf, sizeof(buf), ":%zx,%zx", offset, kChunk);
188	    auto body = sess.send_command("qXfer:features:read:" + annex + buf);
189	    if (body.empty())
190	      throw std::runtime_error("qXfer empty reply for " + annex);
191	    const char marker = body.front();
192	    if (marker != 'l' && marker != 'm')
193	      throw std::runtime_error("qXfer non-l/m reply for " + annex + ": "
194	                               + std::string{marker});
195	    accum.append(body.substr(1));
196	    if (marker == 'l') return accum;
197	    offset += body.size() - 1;
198	  }
199	}
200	
201	// Walks target.xml and every <xi:include> annex, returning the merged
202	// register-name -> packet-number map.
203	inline auto discover_reg_map(gdbstub::Session& sess) -> gdbstub::RegMap
204	{
205	  gdbstub::RegMap map;
206	  const auto target_xml = fetch_feature_xml(sess, "target.xml");
207	  unsigned next = 0;
208	  for (const auto& annex : gdbstub::parse_target_xml(target_xml)) {
209	    const auto annex_xml = fetch_feature_xml(sess, annex);
210	    gdbstub::parse_feature_xml(annex_xml, map, next);
211	  }
212	  return map;
213	}
214	
215	// Sends one P packet whose body is built by the supplied encoder. A
216	// missing register name is silently skipped: not every QEMU build
217	// advertises every PMP slot or extension CSR, so absence isn't fatal.
218	template<class Session, class Encoder>
219	inline void try_write_named(Session& sess,
220	                            const gdbstub::RegMap& map,
221	                            const std::string& name,
222	                            Encoder&& encoder)
223	{
224	  const auto reg_num = map.find(name);
225	  if (!reg_num) return;
226	  auto reply = sess.send_command(encoder(*reg_num));
227	  if (reply != "OK")
