/* Drain markers and fail-fast helper shared by all C-level round-trip
 * fixtures (rt_c_hello.c, rt_c_printf.c, rt_c_file_io.c).
 *
 * The fixtures are timing-aware: only the span between rt_phase_qemu1_drain()
 * and rt_phase_vsim_drain() may touch libgloss / sim_control MMIO. Outside
 * that window the program runs on QEMU virt, which has no peripheral at
 * 0xE0080000.
 */

#ifndef RT_C_HELPERS_H
#define RT_C_HELPERS_H

#include <stdint.h>
#include <stdio.h>

/* Matches src/platform/sim_control.hpp:32 SimCommand::FAILED. */
#define SIM_CONTROL_REG (*(volatile uint32_t*) 0xE0080000)
#define SIM_FAILED 0x01234569u

/* Plugin- / handoff-controller-recognized drain markers (CSR 0x7C0,
 * uimm 0 = ENTER, uimm 1 = EXIT). Match insn_match.h.
 *
 * Each helper exposes a global `_hybrid_{enter,exit}_pc` label co-located
 * with the csrwi insn. The labels are inert in CSR mode and consumed by
 * the PC-trigger mode driver (resolved via `nm --defined-only`). Because
 * each fixture calls each helper exactly once, the labels stay unique. */
static inline void rt_phase_qemu1_drain(void)
{
  __asm__ __volatile__(".globl _hybrid_enter_pc\n"
                       "_hybrid_enter_pc:\n"
                       "csrwi 0x7C0, 0\n");
}
static inline void rt_phase_vsim_drain(void)
{
  __asm__ __volatile__(".globl _hybrid_exit_pc\n"
                       "_hybrid_exit_pc:\n"
                       "csrwi 0x7C0, 1\n");
}

/* Vsim-only failure path: writes SimCommand::FAILED so vsim's
 * handle_sim_command (sim_control.hpp:188) sets exits=1 and the simulator
 * loop returns 1 before the handoff fires. The harness sees RC=1 vs
 * EXPECT_RC=0 and reports a failure. Bypasses QEMU2 entirely. */
__attribute__((noreturn)) static inline void rt_fail(void)
{
  fflush(stdout);
  SIM_CONTROL_REG = SIM_FAILED;
  for (;;) {
  }
}

/* RISC-V semihosting calls. Only safe in the QEMU2 phase (after
 * rt_phase_vsim_drain): QEMU is spawned with -semihosting-config
 * enable=on,target=native (qemu_handback.hpp:131-132) so the magic
 * slli/ebreak/srai triple is intercepted before reaching mtvec. vsim
 * does NOT implement semihosting, so executing these inside the vsim
 * span would route to m_trap_entry -> exception_handler and loop. */
static inline void rt_semihost_writes(const char* s)
{
  register long a0 __asm__("a0") = 0x04; /* SYS_WRITE0 */
  register long a1 __asm__("a1") = (long) (uintptr_t) s;
  __asm__ __volatile__(".option push\n"
                       ".option norvc\n"
                       "slli x0, x0, 0x1f\n"
                       "ebreak\n"
                       "srai x0, x0, 0x7\n"
                       ".option pop\n"
                       :
                       : "r"(a0), "r"(a1)
                       : "memory");
}

#endif /* RT_C_HELPERS_H */

/* rt_c_v_csrs.c - Round-trip fixture: V scalar CSR survival.
 *
 * Exercises vxsat, vxrm, vcsr, vtype, vl, and vstart across the
 * QEMU1 -> vsim -> QEMU2 handoff.
 *
 * Phase 1 (QEMU1): drain marker only (no V instructions; plugin PC
 *   drain constraint).
 * Phase 2 (vsim):  configure known V CSR values, then drain.
 *   - vsetvli: vl=8, vtype=e32/m1/ta/ma (0xD0)
 *   - csrw vxsat=1, vxrm=2, vstart=3 (vstart last: vsetvli resets it to 0)
 * Phase 3 (QEMU2): read V CSRs via csrr and verify each expected value.
 *   mstatus.VS is restored by ResumeDriver so no extra csrs needed.
 *   vstart is read before any V instruction so it holds the restored value.
 *
 * vcsr[0] = vxsat, vcsr[2:1] = vxrm -> expected vcsr = (2<<1)|1 = 5.
 * vtype: vsew=e32=010 at bits[5:3], vta=1 at bit6, vma=1 at bit7 -> 0xD0.
 */
#include "runtime/rt_c_helpers.h"

#include <stdint.h>

int main(void)
{
  /* Phase 1 (QEMU1): no V instructions before the drain marker. */
  rt_phase_qemu1_drain();

  /* Phase 2 (vsim): set known V CSR values.
   * crt0.S already set mstatus.VS=non-Off so vsetvli doesn't trap.
   * vstart must be written last: vsetvli resets vstart to 0. */
  asm volatile(
    "li     a0, 8\n"
    "vsetvli t0, a0, e32, m1, ta, ma\n"  /* vl=8, vtype=0xD0 */
    "li     t1, 1\n"
    "csrw   vxsat, t1\n"
    "li     t1, 2\n"
    "csrw   vxrm,  t1\n"
    "li     t1, 3\n"
    "csrw   vstart, t1\n"
    ::: "t0", "t1", "a0", "memory");

  rt_phase_vsim_drain();

  /* Phase 3 (QEMU2): verify V CSRs survived the round-trip.
   * Read vstart first, before any V instruction resets it to 0. */
  uint64_t vstart_out, vxsat_out, vxrm_out, vcsr_out, vtype_out, vl_out;
  asm volatile(
    "csrr %0, vstart\n"
    "csrr %1, vxsat\n"
    "csrr %2, vxrm\n"
    "csrr %3, vcsr\n"
    "csrr %4, vtype\n"
    "csrr %5, vl\n"
    : "=r"(vstart_out), "=r"(vxsat_out), "=r"(vxrm_out),
      "=r"(vcsr_out),   "=r"(vtype_out), "=r"(vl_out));

  int ok = 1;
  if (vl_out     != 8u)    { rt_semihost_writes("FAIL vl\n");     ok = 0; }
  if (vxsat_out  != 1u)    { rt_semihost_writes("FAIL vxsat\n");  ok = 0; }
  if (vxrm_out   != 2u)    { rt_semihost_writes("FAIL vxrm\n");   ok = 0; }
  if (vcsr_out   != 5u)    { rt_semihost_writes("FAIL vcsr\n");   ok = 0; }
  if (vtype_out  != 0xD0u) { rt_semihost_writes("FAIL vtype\n");  ok = 0; }
  if (vstart_out != 3u)    { rt_semihost_writes("FAIL vstart\n"); ok = 0; }

  if (ok)
    rt_semihost_writes("rt_c_v_csrs: PASS\n");
  else
    rt_semihost_writes("rt_c_v_csrs: FAIL\n");
  return ok ? 0 : 1;
}

