// Pins the contract of HandoffSite + compute_handoff_pc, which the QEMU TCG
// plugin uses to compute the post-trigger resume PC without reading the
// architectural PC register at run time. Reading PC via the gdbstub layer
// inside an exec callback returns a stale value when V instructions retire
// just before the trigger (TCG defers PC writes); capturing vaddr/size at
// translate time avoids the lag entirely.

#include "hybrid/handoff_site.h"
#include "hybrid/insn_match.h"

#define DOCTEST_CONFIG_IMPLEMENT_WITH_MAIN
#include <doctest.h>

#include <cstdint>

TEST_CASE("compute_handoff_pc returns vaddr + size for a 4-byte trigger")
{
  const HandoffSite site{HYBRID_HANDOFF_ENTER, 0x80001234ULL, 4u};
  CHECK(compute_handoff_pc(&site) == 0x80001238ULL);
}

TEST_CASE("compute_handoff_pc honors a compressed (2-byte) trigger")
{
  // PC-mode allows a fixture to park _hybrid_enter_pc on a compressed insn.
  const HandoffSite site{HYBRID_HANDOFF_ENTER, 0x80002000ULL, 2u};
  CHECK(compute_handoff_pc(&site) == 0x80002002ULL);
}

TEST_CASE("HandoffSite preserves the kind across the trans -> exec hop")
{
  const HandoffSite enter{HYBRID_HANDOFF_ENTER,   0x1000ULL, 4u};
  const HandoffSite exit_{HYBRID_HANDOFF_EXIT,    0x2000ULL, 4u};
  const HandoffSite rt   {HYBRID_HANDOFF_RUNTIME, 0x3000ULL, 4u};
  CHECK(enter.kind == HYBRID_HANDOFF_ENTER);
  CHECK(exit_.kind == HYBRID_HANDOFF_EXIT);
  CHECK(rt.kind    == HYBRID_HANDOFF_RUNTIME);
}

