// Translation-time capture of a handoff trigger insn. The QEMU TCG plugin
// allocates one of these per matched insn during vcpu_tb_trans and forwards
// the pointer as exec-callback userdata. compute_handoff_pc(site) returns
// the PC at which vsim should resume (i.e. the architectural PC immediately
// after the trigger insn retires).
//
// This indirection exists because qemu_plugin_read_register("pc") inside an
// exec callback returns a stale PC when V instructions retire just before
// the trigger -- TCG defers PC writes for performance and the gdbstub
// readback observes the lag. vaddr/size are deterministic at translate time
// (qemu_plugin_insn_vaddr/size), so vaddr+size is a lag-free post-trigger
// PC. Same predicate, two consumers: the plugin (C) and a doctest unit
// test (C++).
//
// Lifetime: sites are heap-allocated in vcpu_tb_trans and never freed --
// the plugin has no "TB invalidated" hook and trigger sites are bounded by
// the fixture's text (typically 1-2 csrwi insns).

#ifndef HYBRID_HANDOFF_SITE_H
#define HYBRID_HANDOFF_SITE_H

#include "hybrid/insn_match.h"

#include <stdint.h>

#ifdef __cplusplus
extern "C" {
#endif

typedef struct HandoffSite
{
  hybrid_handoff_kind kind;
  uint64_t            vaddr;
  uint32_t            size;
} HandoffSite;

static inline uint64_t compute_handoff_pc(const HandoffSite* site)
{
  return site->vaddr + (uint64_t) site->size;
}

#ifdef __cplusplus
}  // extern "C"
#endif

#endif  // HYBRID_HANDOFF_SITE_H

